// ===== 查询函数 =====

/**
 * 获取所有初中学校列表
 * @returns {string[]} 初中学校名称列表
 */
export function getJuniorSchoolList() {
  const schools = new Set();
  dingxiangData.forEach(item => {
    if (item.juniorSchool) {
      schools.add(item.juniorSchool);
    }
  });
  return Array.from(schools).sort((a, b) => a.localeCompare(b, 'zh-CN'));
}

/**
 * 获取老九所高中简称列表
 * @returns {string[]} 老九所高中简称
 */
export function getOldNineSchoolList() {
  return ["一中", "二中", "三中", "四中", "格致", "八中", "福高", "附中", "长一"];
}

/**
 * 获取所有学校简称列表（老九所 + 其他省一级达标高中）
 * @returns {string[]} 所有高中简称
 */
export function getAllSchoolList() {
  return CONFIG.allHighSchools;
}

/**
 * 获取所有高中简称列表（用于定向生查询）
 * @returns {string[]} 所有高中简称
 */
export function getAllHighSchools() {
  return CONFIG.allHighSchools;
}

/**
 * 查询定向生数据
 * @param {object} filters - 筛选条件
 * @param {number} filters.year - 年份
 * @param {string[]} filters.highSchools - 高中简称数组
 * @param {string} [filters.juniorSchool] - 初中学校名称（可选）
 * @returns {object[]} 定向生数据列表
 */
export function queryDingxiangData(filters) {
  const { year, highSchools, juniorSchool } = filters;
  
  return dingxiangData.filter(item => {
    // 年份筛选
    if (year && item.year !== year) {
      return false;
    }
    
    // 高中筛选
    if (highSchools && highSchools.length > 0 && !highSchools.includes(item.highSchool)) {
      return false;
    }
    
    // 初中筛选（模糊匹配）
    if (juniorSchool && item.juniorSchool !== juniorSchool) {
      return false;
    }
    
    return true;
  });
}
